// ── StatCard ──────────────────────────────────────────────────────────────────
export function StatCard({ icon, iconBg, value, label, trend }) {
  const [hov, setHov] = React.useState(false);
  return (
    <div
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        background: hov ? "var(--surface2)" : "var(--surface)",
        border: `1px solid ${hov ? "var(--border2)" : "var(--border)"}`,
        borderRadius: 14,
        padding: "18px 20px",
        display: "flex",
        alignItems: "center",
        gap: 16,
        transition: "all .2s",
        cursor: "default",
        transform: hov ? "translateY(-2px)" : "none",
        boxShadow: hov ? "var(--shadow)" : "none",
      }}
    >
      <div
        style={{
          fontSize: 26,
          width: 50,
          height: 50,
          borderRadius: 12,
          background: iconBg || "var(--gold-dim)",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          flexShrink: 0,
        }}
      >
        {icon}
      </div>
      <div>
        <div
          style={{
            fontFamily: "var(--font-display)",
            fontSize: 32,
            fontWeight: 700,
            lineHeight: 1,
            color: "var(--text)",
          }}
        >
          {value}
        </div>
        <div
          style={{
            fontSize: 11,
            color: "var(--muted)",
            marginTop: 4,
            fontWeight: 600,
            textTransform: "uppercase",
            letterSpacing: "1px",
          }}
        >
          {label}
        </div>
      </div>
    </div>
  );
}

// ── Sidebar ───────────────────────────────────────────────────────────────────
const NAV = [
  { id: "dashboard", icon: "◈", label: "Dashboard" },
  { id: "books", icon: "⊟", label: "Books" },
  { id: "users", icon: "⊙", label: "Users" },
  { id: "loans", icon: "⇄", label: "Loans" },
  { id: "fines", icon: "⊘", label: "Fines" },
];

export function Sidebar({ active, onNav }) {
  return (
    <aside
      style={{
        position: "fixed",
        left: 0,
        top: 0,
        bottom: 0,
        width: "var(--sw)",
        background: "var(--bg2)",
        borderRight: "1px solid var(--border)",
        display: "flex",
        flexDirection: "column",
        zIndex: 100,
      }}
    >
      {/* Logo */}
      <div
        style={{
          padding: "28px 24px 22px",
          borderBottom: "1px solid var(--border)",
        }}
      >
        <div
          style={{
            fontFamily: "var(--font-display)",
            fontSize: 26,
            fontWeight: 700,
            color: "var(--gold)",
            letterSpacing: "-.5px",
          }}
        >
          LibraMS
        </div>
        <div
          style={{
            fontSize: 10,
            color: "var(--muted)",
            letterSpacing: "2px",
            textTransform: "uppercase",
            marginTop: 4,
          }}
        >
          Library Management
        </div>
      </div>

      {/* Nav */}
      <nav
        style={{
          flex: 1,
          padding: "18px 12px",
          display: "flex",
          flexDirection: "column",
          gap: 2,
        }}
      >
        {NAV.map((n) => {
          const isActive = active === n.id;
          return (
            <button
              key={n.id}
              onClick={() => onNav(n.id)}
              style={{
                display: "flex",
                alignItems: "center",
                gap: 11,
                padding: "9px 13px",
                borderRadius: 9,
                border: isActive
                  ? "1px solid rgba(201,150,58,.2)"
                  : "1px solid transparent",
                background: isActive ? "var(--gold-dim)" : "transparent",
                color: isActive ? "var(--gold)" : "var(--muted)",
                fontSize: 13.5,
                fontWeight: isActive ? 600 : 500,
                cursor: "pointer",
                fontFamily: "var(--font-body)",
                transition: "all .15s",
                width: "100%",
                textAlign: "left",
              }}
              onMouseEnter={(e) => {
                if (!isActive) {
                  e.currentTarget.style.background = "var(--surface)";
                  e.currentTarget.style.color = "var(--text2)";
                }
              }}
              onMouseLeave={(e) => {
                if (!isActive) {
                  e.currentTarget.style.background = "transparent";
                  e.currentTarget.style.color = "var(--muted)";
                }
              }}
            >
              <span
                style={{
                  fontSize: 16,
                  width: 20,
                  textAlign: "center",
                  flexShrink: 0,
                }}
              >
                {n.icon}
              </span>
              <span>{n.label}</span>
              {isActive && (
                <span
                  style={{
                    marginLeft: "auto",
                    width: 5,
                    height: 5,
                    borderRadius: "50%",
                    background: "var(--gold)",
                  }}
                />
              )}
            </button>
          );
        })}
      </nav>

      {/* Footer */}
      <div style={{ padding: "0 14px 20px" }}>
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 8,
            background: "var(--surface)",
            border: "1px solid var(--border)",
            borderRadius: 8,
            padding: "8px 11px",
            marginBottom: 6,
          }}
        >
          <div
            style={{
              width: 6,
              height: 6,
              borderRadius: "50%",
              background: "var(--teal)",
              animation: "pulse 2s infinite",
              flexShrink: 0,
            }}
          />
          <span
            style={{
              fontFamily: "var(--font-mono)",
              fontSize: 10.5,
              color: "var(--muted)",
            }}
          >
            localhost:9095
          </span>
        </div>
        <div
          style={{
            fontSize: 9.5,
            color: "var(--muted)",
            paddingLeft: 4,
            letterSpacing: ".5px",
          }}
        >
          Spring Boot · Spring Cloud
        </div>
      </div>
    </aside>
  );
}

// ── Toast Container ───────────────────────────────────────────────────────────
const TC = { success: "var(--teal)", error: "var(--red)", info: "var(--blue)" };
const TI = { success: "✓", error: "✕", info: "i" };

export function ToastContainer({ toasts, onRemove }) {
  return (
    <div
      style={{
        position: "fixed",
        top: 20,
        right: 20,
        zIndex: 999,
        display: "flex",
        flexDirection: "column",
        gap: 8,
        pointerEvents: "none",
      }}
    >
      {toasts.map((t) => (
        <div
          key={t.id}
          onClick={() => onRemove(t.id)}
          style={{
            background: "var(--surface)",
            border: "1px solid var(--border2)",
            borderLeft: `3px solid ${TC[t.type] || TC.info}`,
            borderRadius: 10,
            padding: "11px 16px",
            fontSize: 13.5,
            fontWeight: 500,
            boxShadow: "var(--shadow)",
            display: "flex",
            alignItems: "center",
            gap: 10,
            animation: "slideIn .3s ease",
            pointerEvents: "auto",
            maxWidth: 340,
            cursor: "pointer",
            color: "var(--text)",
            fontFamily: "var(--font-body)",
          }}
        >
          <span
            style={{
              width: 20,
              height: 20,
              borderRadius: "50%",
              background: TC[t.type],
              color: "#fff",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontSize: 11,
              fontWeight: 700,
              flexShrink: 0,
            }}
          >
            {TI[t.type]}
          </span>
          <span>{t.msg}</span>
        </div>
      ))}
    </div>
  );
}
